sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.admin-workspace{

    padding:60px;
    background:#f5f7fa;
    min-height:100vh;

}

.workspace-header{

    text-align:center;
    margin-bottom:50px;

}

.workspace-header h1{

    color:#0F4C81;
    font-size:42px;
    margin-bottom:15px;

}

.workspace-header p{

    color:#666;
    font-size:18px;

}

.summary-grid{

    display:flex;
    justify-content:center;
    gap:25px;
    flex-wrap:wrap;

}

.summary-card{

    width:230px;
    background:white;
    padding:30px;
    border-radius:12px;
    text-align:center;
    box-shadow:0 8px 20px rgba(0,0,0,.08);
    transition:.3s;

}

.summary-card:hover{

    transform:translateY(-6px);

}

.summary-card h3{

    color:#666;
    margin-bottom:15px;

}

.summary-card h2{

    color:#0F4C81;
    font-size:38px;

}
.pending-section{

    margin-top:60px;

}

.pending-section h2{

    color:#0F4C81;
    margin-bottom:20px;

}

.pending-table{

    width:100%;
    border-collapse:collapse;
    background:white;
    border-radius:12px;
    overflow:hidden;
    box-shadow:0 8px 20px rgba(0,0,0,.08);

}

.pending-table th{

    background:#0F4C81;
    color:white;
    padding:16px;
    text-align:left;

}

.pending-table td{

    padding:15px;
    border-bottom:1px solid #e5e5e5;

}

.pending-table tr:hover{

    background:#f7f9fc;

}
.tasks-section{

    margin-top:60px;

}

.tasks-section h2{

    color:#0F4C81;
    margin-bottom:20px;

}

.tasks-table{

    width:100%;
    border-collapse:collapse;
    background:#ffffff;
    border-radius:12px;
    overflow:hidden;
    box-shadow:0 8px 20px rgba(0,0,0,.08);

}

.tasks-table th{

    background:#0F4C81;
    color:#ffffff;
    padding:16px;
    text-align:left;

}

.tasks-table td{

    padding:15px;
    border-bottom:1px solid #e5e5e5;

}

.tasks-table tr:hover{

    background:#f7f9fc;

}

sp_widget.script:
(function() {

    data.total = 0;
    data.pending = 0;
    data.approved = 0;
    data.completed = 0;

    data.requests = [];

    var gr = new GlideRecord('x_1958816_enterp_0_network_request');
    gr.query();

    while(gr.next()){

        data.total++;

        var state = gr.getDisplayValue('state');

        if(state == "Pending")
            data.pending++;

        if(state == "Approved")
            data.approved++;

        if(state == "Completed")
            data.completed++;

        if(state == "Pending"){

            data.requests.push({

                number : gr.getDisplayValue(),
                type : gr.getDisplayValue('request_type'),
                requester : gr.getDisplayValue('requested_for'),
                priority : gr.getDisplayValue('priority'),
                state : state

            });

        }

    }
data.tasks = [];

var task = new GlideRecord('x_1958816_enterp_0_fulfillment_task');
task.query();

while(task.next()){

    data.tasks.push({

        number : task.getDisplayValue(),
        short_description : task.getDisplayValue('short_description'),
        assigned_to : task.getDisplayValue('assigned_to'),
        state : task.getDisplayValue('state')

    });

}
})();
